/**
 * MedX required forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Required field detection and aria-required.
 */
const REQUIRED_TOKENS = Object.freeze({
  primary: { value: "forms-required-primary", scope: "forms" },
  secondary: { value: "forms-required-secondary", scope: "forms" },
  muted: { value: "forms-required-muted", scope: "forms" },
  accent: { value: "forms-required-accent", scope: "forms" },
  surface: { value: "forms-required-surface", scope: "forms" },
});

const REQUIRED_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const REQUIRED_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const requiredRegistry = new Map();
const REQUIRED_listeners = new Set();
let REQUIRED_seq = 0;

function createRequiredId(prefix = "medx-forms-required") {
  REQUIRED_seq += 1;
  return `${prefix}-${REQUIRED_seq}`;
}

function registerRequired(config = {}) {
  const entryId = config.id ?? createRequiredId();
  const preset = REQUIRED_PRESETS[config.preset ?? "default"] ?? REQUIRED_PRESETS.default;
  const token = REQUIRED_TOKENS[config.token ?? preset.token] ?? REQUIRED_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: REQUIRED_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  requiredRegistry.set(entryId, entry);
  notifyRequiredListeners("register", entry);
  return entry;
}

function updateRequired(id, patch = {}) {
  const entry = requiredRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyRequiredListeners("update", entry);
  return entry;
}

function resolveRequired(id) {
  const entry = requiredRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listRequiredEntries(filter = {}) {
  let items = Array.from(requiredRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onRequiredEvent(listener) {
  REQUIRED_listeners.add(listener);
  return () => REQUIRED_listeners.delete(listener);
}

function notifyRequiredListeners(type, entry) {
  for (const listener of REQUIRED_listeners) {
    try {
      listener({ type, entry, registrySize: requiredRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:required] listener error", err.message);
    }
  }
}

function getRequiredMetrics() {
  const items = listRequiredEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(REQUIRED_TOKENS).length,
    presets: Object.keys(REQUIRED_PRESETS).length,
  };
}

async function runMedxRequired() {
  console.log("[medx:ui:forms:required] runtime initialized");
  console.log(`[medx:ui:forms:required] tokens=${Object.keys(REQUIRED_TOKENS).length} presets=${Object.keys(REQUIRED_PRESETS).length}`);

  const events = [];
  onRequiredEvent((e) => events.push(e.type));

  const domains = Object.keys(REQUIRED_SUPPLY_CHAIN);
  const presets = Object.keys(REQUIRED_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerRequired({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/required" },
    });
  }

  const first = listRequiredEntries()[0];
  if (first) updateRequired(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getRequiredMetrics();
  const resolved = first ? resolveRequired(first.id) : null;

  console.log(`[medx:ui:forms:required] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:required] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:required] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:required] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:required] bootstrap complete");
}

module.exports = runMedxRequired;
